void solve(int CASE)
{
	ll n; cin >> n;
	var p = vector<tuple<ll, ll, ll>>(n + 1);
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n) {
		ll a, b, c; cin >> a >> b >> c;
		p[i] = { a,b,c };
	}
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var _1 = vector<ll>(n + 1);
	fa(i, 1, n) {
		const var& [a, b, c] = p[i];
		if (c >= 0)_1[i] = -1;
		else _1[i] = (1 - b) / c;
	}

	var check = [&](ll mid)->bool {
		var dl = vector<ll>(n + 1, -1);
		fa(i, 1, n) {
			// 二分算单独每个点的 deadline
			const var& [a, b, c] = p[i];
			var check = [&](__int128 x)->bool {
				__int128 res = 0, len = 0;
				if (_1[i] == -1) {
					len = mid - x + 1;
					res = (x + mid) * len / 2 * c + b * len;
				}
				else {
					if (_1[i] <= mid) {
						if (x <= _1[i]) {
							len = _1[i] - x + 1;
							res = (x + _1[i]) * len / 2 * c + b * len;
							res += mid - _1[i];
						}
						else res = mid - x + 1;
					}
					else {
						len = mid - x + 1;
						res = (x + mid) * len / 2 * c + b * len;
					}
				}
				return res >= a;
				};
			ll l = 1, r = mid;
			while (l <= r) {
				ll mmid = l + r >> 1;
				if (check(mmid)) {
					dl[i] = mmid;
					l = mmid + 1;
				}
				else r = mmid - 1;
			}

			if (dl[i] == -1)return 0; // 剪枝
		}

		// 偏序映射 dl
		var dfs = [&](var dfs, int now, int fa)->void {
			for (int to : g[now]) {
				if (to == fa)continue;
				dfs(dfs, to, now);
				dl[now] = min(dl[to] - 1, dl[now]);
			}
			};
		dfs(dfs, 1, 0);

		sort(all1(dl));
		fa(i, 1, n)if (dl[i] < i)return 0; // 一个一个排队解决，比 i 还早肯定没空解决这个
		return 1;

		};

	ll l = n, r = 1e9, ans = 0;
	while (l <= r) {
		ll mid = l + r >> 1;
		if (check(mid)) {
			ans = mid;
			r = mid - 1;
		}
		else l = mid + 1;
	}
	cout << ans << endl;
	return;
}
